{
  "citations": [
    {
      "span_start": 158,
      "span_end": 198,
      "span_text": "وَمَا نُنَزِّلُهُ إِلَّا بِقَدَرٍ مَعْلُومٍ",
      "citation_type": "Aya"
    },
    {
      "span_start": 391,
      "span_end": 591,
      "span_text": "إن أحَدَكُمْ يُجْمَعُ خَلْقُهُ في بَطْنِ أُمِّهِ أَرْبَعِينَ يَوْمَاً نُطْفَةً، ثُمَّ يَكُونُ عَلَقَةً مِثْلَ ذلكَ، ثُمَّ يَكُونُ مُضْغَةً مِثْلَ ذلكَ، ثُمَّ يُرْسَلُ المَلَكُ فَيَنْفُخُ فِيهِ الرُّوحَ، وَيُؤْمَرُ بأرْبَعِ كَلِماتٍ: بِكَتْب رِزْقِهِ وَأجَلِهِ وَعَمَلِهِ وَشَقِيٍّ أَوْ سَعِيدٍ",
      "citation_type": "Hadeeth"
    },
    {
      "span_start": 801,
      "span_end": 911,
      "span_text": "وَضَرَبَ الله مَثَلاً قَرْيَةً كَانَتْ آمِنَةً مُطْمَئِنَّةً يَأْتِيهَا رِزْقُهَا رَغَداً مِّطْمَئِنَّا يَأْتِيهَا رِزْقُهَا رَغَدًا مِّطْمئنِّين",
      "citation_type": "Aya"
    },
    {
      "span_start": 1655,
      "span_end": 1855,
      "span_text": "إن أحَدَكُمْ يُجْمَعُ خَلْقُهُ في بَطْنِ أُمِّهِ أَرْبَعِينَ يَوْمَاً نُطْفَةً، ثُمَّ يَكُونُ عَلَقَةً مِثْلَ ذلكَ، ثُمَّ يَكُونُ مُضْغَةً مِثْلَ ذلكَ، ثُمَّ يُرْسَلُ المَلَكُ فَيَنْفُخُ فِيهِ الرُّوحَ، وَيُؤْمَرُ بأرْبَعِ كَلِماتٍ: بِكَتْب رِزْقِهِ وَأجَلِهِ وَعَمَلِهِ وَشَقِيٍّ أَوْ سَعِيدٍ",
      "citation_type": "Hadeeth"
    },
    {
      "span_start": 1885,
      "span_end": 1935,
      "span_text": "وَمَا مِنْ دَابَّةٍ فِي الْأَرْضِ إِلاَّ عَلَى اللَّهِ رِزْقُهَا",
      "citation_type": "Aya"
    },
    {
      "span_start": 1940,
      "span_end": 2000,
      "span_text": "وَكَأَيِّنْ مِنْ دَابَّةٍ لا تَحْمِلُ رِزْقَهَا اللَّهُ يَرْزُقُهَا وَإِيَّاكُمْ",
      "citation_type": "Aya"
    },
    {
      "span_start": 2005,
      "span_end": 2055,
      "span_text": "مَا يَفْتَحِ اللَّهُ لِلنَّاسِ مِنْ رَحْمَةٍ فَلا مُمْسِكَ لَهَا",
      "citation_type": "Aya"
    },
    {
      "span_start": 2060,
      "span_end": 2105,
      "span_text": "وَإِنْ يُرِدْكَ بِخَيْرٍ فَلا رَادَّ لِفَضْلِهِ",
      "citation_type": "Aya"
    },
    {
      "span_start": 2155,
      "span_end": 2275,
      "span_text": "فِي يَوْمَيْنِ وَتَجْعَلُونَ لَهُ أَندَاداً ذَلِكَ رَبُّ العالمين وَجَعَلَ فِيهَا رَوَاسِيَ مِن فَوْقِهَا وَبَارَكَ فِيهَا وَقَدَّرَ فِيهَآ أَقْوَاتَهَا في أَرْبَعَةِ أَيَّامٍ سَوَآءً لِّلسَّآئِلِينَ",
      "citation_type": "Aya"
    },
    {
      "span_start": 2325,
      "span_end": 2367,
      "span_text": "وَمَا نُنَزِّلُهُ إِلاَّ بِقَدَرٍ مَّعْلُومٍ",
      "citation_type": "Aya"
    },
    {
      "span_start": 2417,
      "span_end": 2537,
      "span_text": "وَضَرَبَ الله مَثَلاً قَرْيَةً كَانَتْ آمِنَةً مُطْمَئِنَّةً يَأْتِيهَا رِزْقُهَا رَغَداً مِّن كُلِّ مَكَانٍ فَكَفَرَتْ بِأَنْعُمِ الله فَأَذَاقَهَا الله لِبَاسَ الجوع والخوف بِمَا كَانُواْ يَصْنَعُونَ",
      "citation_type": "Aya"
    },
    {
      "span_start": 2587,
      "span_end": 2697,
      "span_text": "إِنَّ الذين تَوَفَّاهُمُ الملائكة ظالمي أَنْفُسِهِمْ قَالُواْ فِيمَ كُنتُمْ قَالُواْ كُنَّا مُسْتَضْعَفِينَ فِي الأرض قالوا أَلَمْ تَكُنْ أَرْضُ الله وَاسِعَةً فَتُهَاجِرُواْ فِيهَا",
      "citation_type": "Aya"
    }
  ]
}
